"use strict";(self.webpackChunkclassroom_scrapper_site=self.webpackChunkclassroom_scrapper_site||[]).push([[6946],{4819(e){e.exports=JSON.parse('{"tag":{"label":"AI","permalink":"/tags/ai","allTagsPath":"/tags","count":7,"items":[{"id":"ES119/Module 1/Lec_06_A Search Algorithm and Game Theory Basics","title":"A* Search Algorithm and Game Theory Basics","description":"The A\\\\* search algorithm is a cornerstone of pathfinding and graph traversal, widely used in artificial intelligence and computer science for its efficiency and optimality under certain conditions. It builds upon ideas from Breadth-First Search (BFS) and Dijkstra\'s algorithm by incorporating a heuristic function to guide its search more effectively.","permalink":"/ES119/Module 1/Lec_06_A Search Algorithm and Game Theory Basics"},{"id":"ES119/Module 1/Lecture4_AgentEnvironment","title":"Agent and Environment Representation for Pathfinding","description":"Introduction to Pathfinding Applications","permalink":"/ES119/Module 1/Lecture4_AgentEnvironment"},{"id":"ES119/Module 1/Lecture7_alphabeta","title":"Alpha-Beta Pruning","description":"In adversarial search, the Minimax algorithm provides a theoretical framework for optimal decision-making in zero-sum games. However, its computational complexity renders it impractical for games with large search spaces. Alpha-Beta Pruning is an optimization that drastically reduces the number of nodes evaluated by the Minimax algorithm without affecting the final decision.","permalink":"/ES119/Module 1/Lecture7_alphabeta"},{"id":"ES119/Module 1/Lec_03_Asymptotic Analysis of k-Nearest Neighbors and Sorting Algorithms","title":"Asymptotic Analysis of k-Nearest Neighbors and Sorting Algorithms","description":"The $k$-Nearest Neighbors ($k$-NN) algorithm is a non-parametric, instance-based learning algorithm used for classification and regression. It\'s a lazy learner, meaning it does not construct a general internal model during training; instead, it memorizes the training dataset.","permalink":"/ES119/Module 1/Lec_03_Asymptotic Analysis of k-Nearest Neighbors and Sorting Algorithms"},{"id":"ES119/Module 1/Lecture1_HistoricalPersepctives","title":"Introduction to Artificial Intelligence and Historical Perspectives","description":"Welcome to ES119: Principles of AI. In this introductory lecture, we lay the groundwork for understanding Artificial Intelligence, delving into its core definitions, historical milestones, and the underlying computational and biological inspirations.","permalink":"/ES119/Module 1/Lecture1_HistoricalPersepctives"},{"id":"ES119/Module 2/Lec_01_Introduction to Machine Learning Definitions, Applications, and Challenges","title":"Introduction to Machine Learning","description":"Machine Learning (ML) is a transformative field at the confluence of computer science, statistics, and artificial intelligence. It focuses on developing algorithms that enable systems to learn from data, identify intricate patterns, and make informed decisions or predictions without explicit programming. This lecture lays the groundwork by exploring fundamental definitions, a spectrum of real-world applications, and the significant challenges that accompany the advancement of ML.","permalink":"/ES119/Module 2/Lec_01_Introduction to Machine Learning Definitions, Applications, and Challenges"},{"id":"ES119/Module 1/Lecture2_knnAnalysis","title":"k-NN Asymptotic Analysis","description":"k-Nearest Neighbors (k-NN) Asymptotic Analysis","permalink":"/ES119/Module 1/Lecture2_knnAnalysis"}],"unlisted":false}}')}}]);